.drop-container {
  --loader-bg: #ffffff;
  --loader-border-color: #cbd5e1;
  --loader-border-active: #3b82f6;
  --loader-text-primary: #1e293b;
  --loader-text-secondary: #64748b;
  --loader-success-bg: #f0fdf4;
  --loader-success-border: #4ade80;

  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 2.5rem 2rem;
  border: 2px dashed var(--loader-border-color);
  border-radius: 12px;
  background-color: var(--loader-bg);
  cursor: pointer;
  transition: all 0.2s ease-in-out;
  text-align: center;
  min-height: 200px;
  position: relative;

  // Hover state
  &:hover {
    border-color: var(--loader-text-secondary);
    background-color: #f8fafc;
  }

  // Active Drag-and-Drop State managed via Signal class binding
  &--active {
    border-color: var(--loader-border-active);
    background-color: #eff6ff;
    transform: scale(1.01);

    .upload-icon {
      transform: translateY(-4px);
      color: var(--loader-border-active);
    }
  }

  .drop-illustration {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
    pointer-events: none; // Prevents nested text from flickering drag events

    .upload-icon {
      font-size: 2.5rem;
      transition: transform 0.2s ease;
    }

    p {
      margin: 0;
      font-size: 1rem;
      color: var(--loader-text-primary);
      font-weight: 500;
    }

    .file-status {
      color: #16a34a;

